4	 pub fn scan_directory(dir: &Path) -> Vec<String> {
5	     let mut files = Vec::new();
6	     if let Ok(entries) = fs::read_dir(dir) {
7	         for entry in entries.flatten() {
8	             let path = entry.path();
9	             if path.is_file() {
10	                 files.push(path.to_str().unwrap().to_string());
11	             } else if path.is_dir() {
12	                 files.extend(scan_directory(&path));
13	             }
14	         }
15	     }
16	     files
17	 }
